import{_ as a,o as t,c as o,a4 as s}from"./chunks/framework.CDpUjPX_.js";const h=JSON.parse('{"title":"Arquitetura do Crawler","description":"","frontmatter":{},"headers":[],"relativePath":"motores/crawler-arquitetura.md","filePath":"motores/crawler-arquitetura.md"}'),r={name:"motores/crawler-arquitetura.md"};function d(c,e,i,n,l,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="arquitetura-do-crawler" tabindex="-1">Arquitetura do Crawler <a class="header-anchor" href="#arquitetura-do-crawler" aria-label="Permalink to &quot;Arquitetura do Crawler&quot;">​</a></h1><blockquote><p>Crawler — Web Crawler com Scrapling. Arquitetura modular com sub-componentes especializados para crawling stealth em escala.</p></blockquote><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><p>O Crawler usa <strong>Scrapling</strong> (<code>scrapling&gt;=0.2.9</code>, instalado via pip) como framework de scraping. A classe principal <code>ScraplingCrawlerService</code> em <code>app/engines/crawler/service.py</code> orquestra o crawling com 3 niveis de stealth, proxy rotation, retries, deteccao de bloqueio e extracao via CSS selectors.</p><p>A arquitetura e composta por sub-componentes independentes que se coordenam via Redis, permitindo operacao cross-worker (Celery):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ScraplingCrawlerService</span></span>
<span class="line"><span>├── fetch_html(url, method)     # Busca HTML com fetcher adequado</span></span>
<span class="line"><span>├── search(target, query)       # Busca imagens em um target</span></span>
<span class="line"><span>└── search_paginated(target, query, max_pages)  # Busca com paginacao</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sub-componentes (Redis-backed):</span></span>
<span class="line"><span>├── fingerprint.py              # Browser fingerprint randomization</span></span>
<span class="line"><span>├── proxy_manager.py            # Proxy scoring e rotacao</span></span>
<span class="line"><span>├── throttle.py                 # Rate limiting per-domain adaptativo</span></span>
<span class="line"><span>├── dedup.py                    # URL deduplication per-target</span></span>
<span class="line"><span>├── cache.py                    # Response cache (change detection)</span></span>
<span class="line"><span>├── link_extractor.py           # Extracao de URLs/imagens + honeypot detection</span></span>
<span class="line"><span>├── url_skip_cache.py           # Skip cache para URLs sem match</span></span>
<span class="line"><span>├── google_images_direct.py     # Fallback Google Images sem API key</span></span>
<span class="line"><span>├── stats.py                    # Contadores de crawling</span></span>
<span class="line"><span>└── user_agents.py              # Pool de User-Agents reais</span></span></code></pre></div><hr><h2 id="scrapling-fetchers" tabindex="-1">Scrapling Fetchers <a class="header-anchor" href="#scrapling-fetchers" aria-label="Permalink to &quot;Scrapling Fetchers&quot;">​</a></h2><p><strong>Arquivo:</strong> <code>app/engines/crawler/service.py</code></p><p>O Scrapling oferece diferentes fetchers para diferentes cenarios. O Kubex usa 3 principais + 1 fallback sincrono:</p><table tabindex="0"><thead><tr><th>Fetcher</th><th>Backend</th><th>Uso</th><th>Velocidade</th><th>Stealth</th></tr></thead><tbody><tr><td><code>AsyncFetcher</code></td><td>curl_cffi (async)</td><td>Sites simples sem JS</td><td>~1-3s</td><td>Baixo</td></tr><tr><td><code>DynamicFetcher</code></td><td>Playwright (async)</td><td>Sites com JS rendering / lazy load</td><td>~3-5s</td><td>Medio</td></tr><tr><td><code>StealthyFetcher</code></td><td>Camoufox (async)</td><td>Sites com anti-bot (Cloudflare, etc)</td><td>~3-8s</td><td>Alto</td></tr><tr><td><code>Fetcher</code> (sync)</td><td>curl_cffi (sync)</td><td>Fallback se nenhum async disponivel</td><td>~1-3s</td><td>Baixo</td></tr></tbody></table><h3 id="graceful-degradation" tabindex="-1">Graceful Degradation <a class="header-anchor" href="#graceful-degradation" aria-label="Permalink to &quot;Graceful Degradation&quot;">​</a></h3><p>Cada fetcher e importado com <code>try/except ImportError</code>. Se o fetcher solicitado nao estiver disponivel, o sistema faz fallback automatico:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>StealthyFetcher (indisponivel) → DynamicFetcher (indisponivel) → AsyncFetcher → Fetcher (sync, via asyncio.to_thread)</span></span></code></pre></div><p>Se o metodo solicitado nao estiver disponivel, um warning e logado e o sistema usa o nivel mais proximo disponivel.</p><h3 id="configuracao-dos-fetchers" tabindex="-1">Configuracao dos Fetchers <a class="header-anchor" href="#configuracao-dos-fetchers" aria-label="Permalink to &quot;Configuracao dos Fetchers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parametro</th><th>Fetcher</th><th>Descricao</th></tr></thead><tbody><tr><td><code>headless=True</code></td><td>Dynamic, Stealthy</td><td>Modo headless (sem janela visivel)</td></tr><tr><td><code>disable_resources</code></td><td>Dynamic, Stealthy</td><td>Bloqueia CSS/fonts/imagens desnecessarias</td></tr><tr><td><code>solve_cloudflare</code></td><td>Stealthy</td><td>Bypass automatico de Cloudflare challenge</td></tr><tr><td><code>hide_canvas</code></td><td>Stealthy</td><td>Oculta canvas fingerprint</td></tr><tr><td><code>block_webrtc</code></td><td>Stealthy</td><td>Bloqueia vazamento de IP real via WebRTC</td></tr><tr><td><code>timeout</code></td><td>Todos</td><td>Timeout em ms (<code>CRAWLER_FETCH_TIMEOUT_MS</code>)</td></tr><tr><td><code>retries</code> / <code>retry_delay</code></td><td>AsyncFetcher</td><td>Retry automatico (nao disponivel em browser fetchers)</td></tr><tr><td><code>impersonate</code></td><td>AsyncFetcher</td><td>TLS fingerprint impersonation (quando <code>STEALTH_TLS_IMPERSONATION=true</code>)</td></tr></tbody></table><h3 id="deteccao-de-bloqueio" tabindex="-1">Deteccao de Bloqueio <a class="header-anchor" href="#deteccao-de-bloqueio" aria-label="Permalink to &quot;Deteccao de Bloqueio&quot;">​</a></h3><p>Status codes tratados como bloqueio (<code>BLOCKED_STATUS_CODES</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>401, 403, 407, 429, 444, 503</span></span></code></pre></div><p>Quando detectado, <code>FetchResult.is_blocked=True</code> e <code>html=None</code>. O circuit breaker per-domain e acionado.</p><hr><h2 id="sub-componentes" tabindex="-1">Sub-componentes <a class="header-anchor" href="#sub-componentes" aria-label="Permalink to &quot;Sub-componentes&quot;">​</a></h2><h3 id="browser-fingerprint-fingerprint-py" tabindex="-1">Browser Fingerprint (<code>fingerprint.py</code>) <a class="header-anchor" href="#browser-fingerprint-fingerprint-py" aria-label="Permalink to &quot;Browser Fingerprint (\`fingerprint.py\`)&quot;">​</a></h3><p>Gera perfis completos de browser com headers HTTP realisticos para evitar deteccao por anti-bot. Cada requisicao recebe um perfil diferente.</p><p><strong>Browsers suportados:</strong> Chrome, Firefox, Safari, Edge</p><p><strong>Headers gerados por perfil:</strong></p><ul><li><code>User-Agent</code> (de <code>user_agents.py</code> — pool de UAs reais 2025-2026)</li><li><code>Accept</code>, <code>Accept-Language</code>, <code>Accept-Encoding</code> (especificos do browser)</li><li><code>Sec-CH-UA</code> e <code>Sec-CH-UA-Platform</code> (Client Hints para Chrome/Edge)</li><li><code>Sec-Fetch-*</code> headers (Site, Mode, User, Dest)</li><li><code>Connection</code>, <code>Cache-Control</code>, <code>Upgrade-Insecure-Requests</code></li><li><code>DNT</code> (aleatorio, somente Firefox)</li></ul><p><strong>Funcoes principais:</strong></p><table tabindex="0"><thead><tr><th>Funcao</th><th>Descricao</th></tr></thead><tbody><tr><td><code>generate_browser_profile(ua?)</code></td><td>Retorna <code>dict[str, str]</code> com headers completos</td></tr><tr><td><code>generate_browser_profile_ordered(ua?)</code></td><td>Retorna <code>list[tuple]</code> com headers em ordem randomizada (anti-fingerprinting por ordem)</td></tr><tr><td><code>generate_referer(url, context)</code></td><td>Gera Referer plausivel (search, navigation, image, social). 15% chance de sem Referer (simula usuarios reais)</td></tr><tr><td><code>adjust_sec_fetch_headers(headers, referer, dest_url)</code></td><td>Ajusta <code>Sec-Fetch-Site</code> baseado no Referer para consistencia com browser real</td></tr><tr><td><code>generate_kubexbot_profile()</code></td><td>Perfil transparente <code>KubexBot/1.0</code> para crawling respeitando robots.txt</td></tr></tbody></table><p><strong>Accept-Language:</strong> Ponderado para pt-BR (brasileiro), com variantes incluindo en-US e es.</p><hr><h3 id="proxy-manager-proxy-manager-py" tabindex="-1">Proxy Manager (<code>proxy_manager.py</code>) <a class="header-anchor" href="#proxy-manager-proxy-manager-py" aria-label="Permalink to &quot;Proxy Manager (\`proxy_manager.py\`)&quot;">​</a></h3><p>Gerenciador inteligente de proxies com scoring Redis-backed. Seleciona o melhor proxy disponivel baseado em metricas de performance.</p><p><strong>Metricas por proxy (Redis HASH, TTL 24h):</strong></p><ul><li><code>total</code> — total de requisicoes</li><li><code>successes</code> — requisicoes bem-sucedidas</li><li><code>blocked</code> — contagem de bloqueios</li><li><code>avg_latency</code> — latencia media (running average)</li><li><code>last_used</code> — timestamp do ultimo uso</li></ul><p><strong>Algoritmo de scoring:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>score = success_rate * (1/avg_latency) * (1 - block_rate) + recency_factor * 0.01</span></span></code></pre></div><ul><li>Proxies com <code>block_rate &gt; 50%</code> sao automaticamente ignorados</li><li>Proxies novos (sem stats) recebem prioridade (high initial score)</li><li><code>recency_factor</code> implementa efeito round-robin (prefere proxies menos usados recentemente)</li></ul><p><strong>Fallback:</strong> Se Redis indisponivel, usa o primeiro proxy da lista. Se nenhum proxy configurado, conexao direta.</p><p><strong>Configuracao:</strong> <code>CRAWLER_PROXY_URLS</code> (lista de URLs <code>http://user:pass@host:port</code>)</p><p><strong>Seguranca:</strong> Credenciais de proxy sao mascaradas (<code>***:***@host:port</code>) em endpoints admin e logs.</p><hr><h3 id="domain-throttle-throttle-py" tabindex="-1">Domain Throttle (<code>throttle.py</code>) <a class="header-anchor" href="#domain-throttle-throttle-py" aria-label="Permalink to &quot;Domain Throttle (\`throttle.py\`)&quot;">​</a></h3><p>Rate limiting adaptativo per-domain coordenado via Redis. Evita sobrecarga de sites alvo e reducao de banimentos.</p><p><strong>Algoritmo:</strong> Adaptacao do Scrapy AutoThrottle (exponential moving average):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>target_delay = latency / target_concurrency</span></span>
<span class="line"><span>new_delay = old_delay + (target_delay - old_delay) / 2.0</span></span>
<span class="line"><span># Clamped entre min_delay e max_delay</span></span></code></pre></div><p><strong>Coordenacao cross-worker:</strong></p><ul><li><code>kubex:throttle:{domain}</code> — slot acquisition via <code>SET NX PX</code> (atomico)</li><li><code>kubex:throttle:delay:{domain}</code> — delay corrente (auto-ajustado, TTL 1h)</li></ul><p><strong>Jitter:</strong> +-30% aleatorio no delay para dificultar deteccao de padrao por anti-bot.</p><p><strong>Configuracao:</strong></p><ul><li><code>CRAWLER_MIN_THROTTLE_DELAY</code> — delay minimo (default 2s)</li><li><code>CRAWLER_MAX_THROTTLE_DELAY</code> — delay maximo (default 30s)</li><li><code>target_concurrency=1.0</code> — concorrencia alvo por dominio</li></ul><p><strong>Fail-safe:</strong> Se Redis indisponivel, aplica <code>min_delay</code> com jitter (nao trava).</p><hr><h3 id="url-dedup-dedup-py" tabindex="-1">URL Dedup (<code>dedup.py</code>) <a class="header-anchor" href="#url-dedup-dedup-py" aria-label="Permalink to &quot;URL Dedup (\`dedup.py\`)&quot;">​</a></h3><p>Evita re-crawling de URLs ja processadas para um target especifico. Redis SET per-target.</p><p><strong>Chave Redis:</strong> <code>kubex:crawler:seen:{target_id}</code> (SET de URLs)</p><p><strong>TTL:</strong> 7 dias — URLs sao reconsideradas apos expiracao.</p><table tabindex="0"><thead><tr><th>Funcao</th><th>Descricao</th></tr></thead><tbody><tr><td><code>is_url_seen(target_id, url)</code></td><td>Verifica se URL ja foi processada</td></tr><tr><td><code>mark_url_seen(target_id, url)</code></td><td>Marca URL como processada (refresh TTL)</td></tr><tr><td><code>clear_seen_urls(target_id)</code></td><td>Limpa todas URLs vistas (retorna count)</td></tr></tbody></table><hr><h3 id="response-cache-cache-py" tabindex="-1">Response Cache (<code>cache.py</code>) <a class="header-anchor" href="#response-cache-cache-py" aria-label="Permalink to &quot;Response Cache (\`cache.py\`)&quot;">​</a></h3><p>Cache de metadados de resposta HTTP para detectar paginas inalteradas entre scans. Evita re-processamento desnecessario.</p><p><strong>Mecanismo:</strong> SHA-256 hash do conteudo HTML (truncado 16 chars). Se o hash nao mudou desde o ultimo scan, a pagina e pulada.</p><p><strong>Chave Redis:</strong> <code>kubex:crawler:cache:{sha256(url)[:16]}</code></p><p><strong>TTL:</strong> 24 horas</p><p><strong>Dados armazenados:</strong> <code>html_hash</code>, <code>etag</code>, <code>last_modified</code> (JSON)</p><table tabindex="0"><thead><tr><th>Funcao</th><th>Descricao</th></tr></thead><tbody><tr><td><code>compute_html_hash(html)</code></td><td>SHA-256 do HTML para change detection</td></tr><tr><td><code>get_cached_response(url)</code></td><td>Retorna metadados cacheados ou None</td></tr><tr><td><code>set_cached_response(url, html_hash, etag?, last_modified?)</code></td><td>Armazena metadados</td></tr></tbody></table><hr><h3 id="link-extractor-link-extractor-py" tabindex="-1">Link Extractor (<code>link_extractor.py</code>) <a class="header-anchor" href="#link-extractor-link-extractor-py" aria-label="Permalink to &quot;Link Extractor (\`link_extractor.py\`)&quot;">​</a></h3><p>Extracao e normalizacao de URLs de paginas HTML. Suporta duas estrategias: CSS selectors (preferida, via Scrapling Response) e regex (fallback).</p><p><strong>Extensoes de imagem suportadas:</strong> <code>.jpg</code>, <code>.jpeg</code>, <code>.png</code>, <code>.gif</code>, <code>.webp</code>, <code>.bmp</code>, <code>.avif</code></p><p><strong>Estrategias de extracao de imagens:</strong></p><table tabindex="0"><thead><tr><th>Funcao</th><th>Estrategia</th><th>Cobertura</th></tr></thead><tbody><tr><td><code>extract_image_urls_from_response()</code></td><td>CSS selectors</td><td><code>img[src]</code>, <code>img[data-src]</code>, <code>img[srcset]</code>, <code>source[srcset]</code></td></tr><tr><td><code>extract_css_background_images()</code></td><td>Regex</td><td>CSS <code>background-image: url(...)</code> inline</td></tr><tr><td><code>extract_lazy_image_urls()</code></td><td>Regex</td><td><code>data-lazy</code>, <code>data-original</code>, <code>data-lazy-src</code>, <code>data-srcset</code></td></tr><tr><td><code>extract_image_urls()</code></td><td>Regex (fallback)</td><td><code>src=&quot;...&quot;</code> apontando para extensoes de imagem</td></tr></tbody></table><p><strong>Extracao de links:</strong></p><table tabindex="0"><thead><tr><th>Funcao</th><th>Estrategia</th><th>Detalhes</th></tr></thead><tbody><tr><td><code>extract_links_from_response()</code></td><td>CSS selectors</td><td>Inclui honeypot detection</td></tr><tr><td><code>extract_links()</code></td><td>Regex (fallback)</td><td><code>href=&quot;...&quot;</code> basico</td></tr></tbody></table><p><strong>Honeypot Detection:</strong></p><p>O <code>link_extractor</code> detecta e ignora links honeypot (armadilhas anti-bot). Verifica:</p><ul><li>Inline styles: <code>display:none</code>, <code>visibility:hidden</code>, <code>opacity:0</code>, posicao absoluta off-screen, dimensoes zero</li><li>Classes CSS: <code>honeypot</code>, <code>honey-pot</code>, <code>hp-field</code>, <code>trap</code>, <code>bot-trap</code>, <code>hidden-link</code>, <code>invisible</code>, <code>nofollow-trap</code></li><li>Estilos do elemento pai (1 nivel acima)</li></ul><p>Links honeypot detectados sao logados como debug e ignorados silenciosamente.</p><p><strong>Limite de HTML:</strong> Extracao limitada a 500 KB de HTML para evitar DoS por paginas gigantes.</p><hr><h3 id="url-skip-cache-url-skip-cache-py" tabindex="-1">URL Skip Cache (<code>url_skip_cache.py</code>) <a class="header-anchor" href="#url-skip-cache-url-skip-cache-py" aria-label="Permalink to &quot;URL Skip Cache (\`url_skip_cache.py\`)&quot;">​</a></h3><p>Cache global de URLs onde nao houve match de pHash. Evita re-download desnecessario em novos targets.</p><p><strong>Diferenca do dedup:</strong> O <code>dedup.py</code> e per-target (mesma URL pode ser relevante para targets diferentes). O <code>url_skip_cache</code> e global — se uma URL nao teve match pHash para nenhum usuario, e marcada globalmente.</p><p><strong>Chave Redis:</strong> <code>kubex:skip:{sha1(url)}</code> (valor &quot;1&quot;)</p><p><strong>TTL:</strong> 7 dias</p><table tabindex="0"><thead><tr><th>Funcao</th><th>Descricao</th></tr></thead><tbody><tr><td><code>mark_no_match(url)</code></td><td>Marca URL como processada sem match</td></tr><tr><td><code>should_skip(url)</code></td><td>Retorna True se deve pular (fail-safe: retorna False se Redis indisponivel)</td></tr></tbody></table><hr><h3 id="google-images-direct-google-images-direct-py" tabindex="-1">Google Images Direct (<code>google_images_direct.py</code>) <a class="header-anchor" href="#google-images-direct-google-images-direct-py" aria-label="Permalink to &quot;Google Images Direct (\`google_images_direct.py\`)&quot;">​</a></h3><p>Fallback para busca reversa no Google Images sem API key. Usado como complemento ao SerpAPI/DDG quando quotas esgotam.</p><p><strong>Mecanismo:</strong></p><ol><li>Monta URL de busca reversa: <code>google.com/searchbyimage?image_url={url}&amp;hl=pt-BR</code></li><li>Usa <code>ScraplingCrawlerService</code> com <code>DynamicFetcher</code> (Playwright) para rendering</li><li>Extrai URLs de resultados via regex (<code>https://...</code> em atributos JSON da pagina)</li><li>Filtra dominios do Google (<code>google.com</code>, <code>gstatic.com</code>, <code>googleapis.com</code>, etc)</li><li>Valida cada URL contra SSRF guard</li></ol><p><strong>Circuit Breaker:</strong> <code>google_direct_circuit</code> (threshold=3, recovery=600s). Se o Google bloquear, para automaticamente por 10 minutos.</p><p><strong>Retorno:</strong> Lista de <code>SearchResult</code> com <code>source=&quot;google_direct&quot;</code> e <code>score=0.5</code>.</p><hr><h3 id="crawler-stats-stats-py" tabindex="-1">Crawler Stats (<code>stats.py</code>) <a class="header-anchor" href="#crawler-stats-stats-py" aria-label="Permalink to &quot;Crawler Stats (\`stats.py\`)&quot;">​</a></h3><p>Contadores de crawling Redis-backed, expostos no admin <code>/metricas</code>.</p><p><strong>Metricas por scan (classe <code>CrawlStats</code>):</strong></p><table tabindex="0"><thead><tr><th>Metrica</th><th>Descricao</th></tr></thead><tbody><tr><td><code>requests_total</code></td><td>Total de requests HTTP</td></tr><tr><td><code>requests_success</code></td><td>Requests bem-sucedidos</td></tr><tr><td><code>requests_blocked</code></td><td>Requests bloqueados (401/403/429/503)</td></tr><tr><td><code>requests_failed</code></td><td>Requests com erro</td></tr><tr><td><code>images_found</code></td><td>Imagens encontradas nas paginas</td></tr><tr><td><code>images_downloaded</code></td><td>Imagens baixadas para hashing</td></tr><tr><td><code>images_matched</code></td><td>Imagens com match pHash</td></tr><tr><td><code>alerts_created</code></td><td>Alertas criados a partir dos matches</td></tr><tr><td><code>elapsed_seconds</code></td><td>Tempo total do scan</td></tr></tbody></table><p><strong>Persistencia Redis:</strong></p><ul><li><strong>Per-target:</strong> <code>kubex:crawler:stats:{target_id}:latest</code> — JSON snapshot do ultimo scan (TTL 7 dias)</li><li><strong>Global:</strong> <code>kubex:crawler:stats:global</code> — HASH com contadores agregados via <code>HINCRBY</code> (persistente, sem TTL)</li></ul><hr><h3 id="user-agents-user-agents-py" tabindex="-1">User Agents (<code>user_agents.py</code>) <a class="header-anchor" href="#user-agents-user-agents-py" aria-label="Permalink to &quot;User Agents (\`user_agents.py\`)&quot;">​</a></h3><p>Pool de User-Agent strings reais de navegadores populares (versoes 2025-2026).</p><p><strong>Browsers incluidos:</strong></p><ul><li>Chrome Desktop (Windows/Mac/Linux) — 7 variantes</li><li>Firefox Desktop (Windows/Mac/Linux/Ubuntu) — 5 variantes</li><li>Safari Desktop (macOS) — 3 variantes</li><li>Edge Desktop (Windows/Mac) — 3 variantes</li><li>Mobile (Chrome Android, Safari iOS, Samsung) — 6 variantes</li></ul><p><strong>Distribuicao:</strong> 80% desktop, 20% mobile (ponderado via <code>random.random()</code>).</p><p><code>get_random_ua(mobile=False, desktop_only=False)</code> — retorna UA aleatorio com ponderacao configuravel.</p><hr><h2 id="ssrf-guard" tabindex="-1">SSRF Guard <a class="header-anchor" href="#ssrf-guard" aria-label="Permalink to &quot;SSRF Guard&quot;">​</a></h2><p><strong>Arquivo:</strong> <code>app/core/ssrf_guard.py</code></p><p>Todas as URLs crawled passam por <code>is_safe_url()</code> antes do fetch. Protege contra Server-Side Request Forgery.</p><p><strong>Bloqueios:</strong></p><ul><li>IPs privados (RFC 1918: <code>10.0.0.0/8</code>, <code>172.16.0.0/12</code>, <code>192.168.0.0/16</code>)</li><li>Loopback (<code>127.0.0.1</code>, <code>::1</code>, <code>localhost</code>)</li><li>Link-local / IMDS (<code>169.254.169.254</code> — AWS/GCP metadata endpoint)</li><li>Schemes nao-HTTP (<code>file://</code>, <code>ftp://</code>, etc)</li><li>Hostnames que resolvem para IPs privados (DNS resolution check)</li></ul><p><strong>Anti-DNS Rebinding:</strong></p><p><code>resolve_and_validate(url)</code> resolve o DNS uma unica vez e retorna o IP resolvido para uso direto no fetch, eliminando a janela TOCTOU (Time-of-Check-Time-of-Use) entre validacao e conexao.</p><p><strong>Versoes:</strong></p><ul><li><code>is_safe_url(url)</code> — sincrono (usado no import-time do service.py)</li><li><code>is_safe_url_async(url)</code> — async via <code>asyncio.to_thread</code> (para codigo async)</li></ul><hr><h2 id="verificacao-robots-txt" tabindex="-1">Verificacao robots.txt <a class="header-anchor" href="#verificacao-robots-txt" aria-label="Permalink to &quot;Verificacao robots.txt&quot;">​</a></h2><p><strong>Funcao:</strong> <code>is_allowed_by_robots(url)</code> em <code>service.py</code></p><p>Verifica se <code>KubexBot</code> tem permissao para acessar a URL via robots.txt do dominio.</p><p><strong>Comportamento:</strong></p><ul><li>Fail-open: se nao conseguir verificar, permite acesso</li><li>Cache Redis 24h por dominio (<code>kubex:robots:{netloc}</code>)</li><li>Limite de 512 KB para robots.txt (protecao contra DoS)</li><li>SSRF guard aplicado ao fetch do robots.txt</li><li>Controlado por <code>KUBEXBOT_ENABLED</code> e <code>KUBEXBOT_RESPECT_ROBOTS_TXT</code></li></ul><hr><h2 id="circuit-breaker" tabindex="-1">Circuit Breaker <a class="header-anchor" href="#circuit-breaker" aria-label="Permalink to &quot;Circuit Breaker&quot;">​</a></h2><p><strong>Arquivo:</strong> <code>app/core/circuit_breaker.py</code></p><p>Circuit breaker per-domain Redis-backed para evitar repetir crawling em dominios que bloquearam o bot.</p><p><strong>Funcao:</strong> <code>get_domain_circuit(domain)</code> retorna instancia sob demanda.</p><p><strong>Configuracao per-domain:</strong></p><ul><li><code>failure_threshold=3</code> — 3 falhas para abrir o circuito</li><li><code>recovery_timeout=600</code> — 10 minutos antes de tentar novamente (HALF_OPEN)</li></ul><p><strong>Estados:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLOSED → requisicoes passam normalmente</span></span>
<span class="line"><span>   ↓ (3 falhas)</span></span>
<span class="line"><span>OPEN → todas requisicoes rejeitadas imediatamente</span></span>
<span class="line"><span>   ↓ (apos 600s)</span></span>
<span class="line"><span>HALF_OPEN → permite 1 requisicao de teste</span></span>
<span class="line"><span>   ↓ sucesso → CLOSED</span></span>
<span class="line"><span>   ↓ falha → OPEN (reinicia timer)</span></span></code></pre></div><p><strong>Fail-open:</strong> Se Redis estiver indisponivel, o circuit breaker assume <code>CLOSED</code> (permite requisicoes).</p><p><strong>Reset manual:</strong> <code>await circuit.reset()</code> disponivel para override administrativo.</p><hr><h2 id="fluxo-de-uma-busca" tabindex="-1">Fluxo de uma Busca <a class="header-anchor" href="#fluxo-de-uma-busca" aria-label="Permalink to &quot;Fluxo de uma Busca&quot;">​</a></h2><p>Sequencia completa de <code>search(target, query)</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Monta URL a partir do template: target.search_url_template.replace(&quot;{query}&quot;, query)</span></span>
<span class="line"><span>2. DomainThrottle.wait(url) — aguarda slot per-domain (Redis SET NX PX)</span></span>
<span class="line"><span>3. fetch_html(url, method):</span></span>
<span class="line"><span>   a. is_safe_url(url) — SSRF guard</span></span>
<span class="line"><span>   b. is_allowed_by_robots(url) — robots.txt check</span></span>
<span class="line"><span>   c. _get_proxy_rotator().get_proxy() — seleciona proxy</span></span>
<span class="line"><span>   d. Executa fetcher (basic/dynamic/stealthy)</span></span>
<span class="line"><span>   e. Detecta bloqueio (status in BLOCKED_STATUS_CODES)</span></span>
<span class="line"><span>   f. Retorna FetchResult(html, response, status_code, is_blocked)</span></span>
<span class="line"><span>4. DomainThrottle.update_delay(url, latency) — ajusta delay adaptativo</span></span>
<span class="line"><span>5. Response Cache check: compute_html_hash() → get_cached_response()</span></span>
<span class="line"><span>   - Se HTML nao mudou → return (skip extraction)</span></span>
<span class="line"><span>   - Se mudou → set_cached_response() e prossegue</span></span>
<span class="line"><span>6. Extracao de imagens:</span></span>
<span class="line"><span>   a. CSS selectors (preferido): extract_image_urls_from_response()</span></span>
<span class="line"><span>   b. Amplifica com: extract_css_background_images() + extract_lazy_image_urls()</span></span>
<span class="line"><span>   c. Fallback regex: extract_image_urls(html[:500_000])</span></span>
<span class="line"><span>7. Retorna (image_urls, FetchResult)</span></span></code></pre></div><h3 id="busca-paginada" tabindex="-1">Busca Paginada <a class="header-anchor" href="#busca-paginada" aria-label="Permalink to &quot;Busca Paginada&quot;">​</a></h3><p><code>search_paginated(target, query, max_pages=3)</code> estende o fluxo acima:</p><ul><li>Segue links de &quot;proxima pagina&quot; via heuristica de paginacao</li><li>Detecta parametros: <code>page</code>, <code>p</code>, <code>pag</code>, <code>pagina</code>, <code>/page/N</code></li><li>Incrementa automaticamente o numero da pagina</li><li>Deduplicacao de imagens entre paginas</li><li>Set de URLs visitadas evita loops</li></ul><hr><h2 id="chaves-redis" tabindex="-1">Chaves Redis <a class="header-anchor" href="#chaves-redis" aria-label="Permalink to &quot;Chaves Redis&quot;">​</a></h2><p>Resumo de todas as chaves Redis usadas pelo crawler:</p><table tabindex="0"><thead><tr><th>Chave</th><th>Componente</th><th>TTL</th><th>Descricao</th></tr></thead><tbody><tr><td><code>kubex:throttle:{domain}</code></td><td>throttle.py</td><td>Dinamico (delay ms)</td><td>Slot de rate limiting</td></tr><tr><td><code>kubex:throttle:delay:{domain}</code></td><td>throttle.py</td><td>1h</td><td>Delay corrente per-domain</td></tr><tr><td><code>kubex:crawler:seen:{target_id}</code></td><td>dedup.py</td><td>7 dias</td><td>SET de URLs processadas</td></tr><tr><td><code>kubex:crawler:cache:{hash}</code></td><td>cache.py</td><td>24h</td><td>Metadados de resposta HTTP</td></tr><tr><td><code>kubex:skip:{sha1}</code></td><td>url_skip_cache.py</td><td>7 dias</td><td>URLs sem match pHash</td></tr><tr><td><code>kubex:proxy:{hash}</code></td><td>proxy_manager.py</td><td>24h</td><td>Stats por proxy (HASH)</td></tr><tr><td><code>kubex:robots:{netloc}</code></td><td>service.py</td><td>24h</td><td>Cache de robots.txt</td></tr><tr><td><code>kubex:crawler:stats:{id}:latest</code></td><td>stats.py</td><td>7 dias</td><td>Ultimo scan per-target</td></tr><tr><td><code>kubex:crawler:stats:global</code></td><td>stats.py</td><td>Permanente</td><td>Contadores globais (HASH)</td></tr><tr><td><code>kubex:cb:crawler_domain:{domain}:*</code></td><td>circuit_breaker.py</td><td>recovery*2</td><td>Circuit breaker per-domain</td></tr></tbody></table>`,146)])])}const g=a(r,[["render",d]]);export{h as __pageData,g as default};
